#usda 1.0
(
    defaultPrim = "Shot"
    subLayers = [
        @./assets.usda@
    ]
)

def Xform "Shot"
{
    def Xform "Set"
    {
        def Xform "ChairA" (
            prepend references = @./assets.usda@</Assets/Chair>
        )
        {
            double3 xformOp:translate = (-2, 0, 0)
            uniform token[] xformOpOrder = ["xformOp:translate"]
        }

        def Xform "ChairB" (
            prepend references = @./assets.usda@</Assets/Chair>
        )
        {
            double3 xformOp:translate = (2, 0, 0)
            uniform token[] xformOpOrder = ["xformOp:translate"]
        }
    }

    def Xform "Lighting" (
        variants = {
            string lightingVariant = "night"
        }
        prepend variantSets = "lightingVariant"
    )
    {
        variantSet "lightingVariant" = {
            "day" {
                def DistantLight "Sun"
                {
                    float inputs:intensity = 50000
                }

            }
            "night" {
                def DomeLight "Sky"
                {
                    float inputs:intensity = 500
                }

            }
        }
    }
}
